import React, { useState, useEffect } from 'react';
import { toast } from 'react-toastify';
import Header from './Header';
import { rfidService } from '../services/rfidService';
import { FaEdit, FaTrash, FaPlus, FaSearch } from 'react-icons/fa';

const RFIDTransactions = () => {
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [userInfo, setUserInfo] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItems, setSelectedItems] = useState([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newItem, setNewItem] = useState({
    rfidNumber: '',
    itemCode: '',
    categoryId: '',
    productId: '',
    designId: '',
    purityId: '',
    grossWeight: '',
    stoneWeight: '',
    diamondHeight: '',
    netWeight: '',
    boxDetails: '',
    size: 0,
    stoneAmount: '',
    diamondAmount: '',
    hallmarkAmount: '',
    makingPerGram: '',
    makingPercentage: '',
    makingFixedAmount: '',
    mrp: '',
    status: 'ApiActive'
  });

  useEffect(() => {
    const storedUserInfo = JSON.parse(localStorage.getItem('userInfo')) || {};
    setUserInfo(storedUserInfo);
    fetchTransactions(storedUserInfo.ClientCode);
  }, []);

  const fetchTransactions = async (clientCode) => {
    setLoading(true);
    try {
      const data = await rfidService.getRFIDTransactions(clientCode);
      setTransactions(data);
    } catch (error) {
      toast.error('Failed to fetch transactions');
      console.error('Error fetching transactions:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateStatus = async (rfidNumber, newStatus) => {
    try {
      await rfidService.updateRFIDTransaction({
        clientCode: userInfo.ClientCode,
        rfidNumber,
        status: newStatus
      });
      toast.success('Status updated successfully');
      fetchTransactions(userInfo.ClientCode);
    } catch (error) {
      toast.error('Failed to update status');
      console.error('Error updating status:', error);
    }
  };

  const handleDelete = async (itemCodes) => {
    if (!window.confirm('Are you sure you want to delete the selected items?')) return;
    
    try {
      await rfidService.deleteLabelledStock(userInfo.ClientCode, itemCodes);
      toast.success('Items deleted successfully');
      fetchTransactions(userInfo.ClientCode);
      setSelectedItems([]);
    } catch (error) {
      toast.error('Failed to delete items');
      console.error('Error deleting items:', error);
    }
  };

  const handleAddItem = async () => {
    try {
      await rfidService.saveRFIDTransaction({
        ...newItem,
        clientCode: userInfo.ClientCode
      });
      toast.success('Item added successfully');
      setShowAddModal(false);
      setNewItem({
        rfidNumber: '',
        itemCode: '',
        categoryId: '',
        productId: '',
        designId: '',
        purityId: '',
        grossWeight: '',
        stoneWeight: '',
        diamondHeight: '',
        netWeight: '',
        boxDetails: '',
        size: 0,
        stoneAmount: '',
        diamondAmount: '',
        hallmarkAmount: '',
        makingPerGram: '',
        makingPercentage: '',
        makingFixedAmount: '',
        mrp: '',
        status: 'ApiActive'
      });
      fetchTransactions(userInfo.ClientCode);
    } catch (error) {
      toast.error('Failed to add item');
      console.error('Error adding item:', error);
    }
  };

  const filteredTransactions = transactions.filter(transaction => 
    transaction.RFIDNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
    transaction.Itemcode.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div style={{ minHeight: '100vh', background: '#f8f9fa' }}>
      <Header userInfo={userInfo} />
      
      <div className="container py-4">
        <div className="d-flex justify-content-between align-items-center mb-4">
          <h2>RFID Transactions</h2>
          <button 
            className="btn btn-primary" 
            onClick={() => setShowAddModal(true)}
          >
            <FaPlus className="me-2" /> Add New Item
          </button>
        </div>

        <div className="card shadow-sm">
          <div className="card-body">
            <div className="d-flex justify-content-between align-items-center mb-4">
              <div className="d-flex align-items-center">
                <div className="input-group">
                  <span className="input-group-text">
                    <FaSearch />
                  </span>
                  <input
                    type="text"
                    className="form-control"
                    placeholder="Search by RFID or Item Code"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
              </div>
              {selectedItems.length > 0 && (
                <button
                  className="btn btn-danger"
                  onClick={() => handleDelete(selectedItems)}
                >
                  <FaTrash className="me-2" /> Delete Selected
                </button>
              )}
            </div>

            <div className="table-responsive">
              <table className="table table-hover">
                <thead>
                  <tr>
                    <th>
                      <input
                        type="checkbox"
                        checked={selectedItems.length === filteredTransactions.length}
                        onChange={(e) => {
                          if (e.target.checked) {
                            setSelectedItems(filteredTransactions.map(t => t.Itemcode));
                          } else {
                            setSelectedItems([]);
                          }
                        }}
                      />
                    </th>
                    <th>RFID Number</th>
                    <th>Item Code</th>
                    <th>Category</th>
                    <th>Product</th>
                    <th>Status</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {loading ? (
                    <tr>
                      <td colSpan="7" className="text-center">Loading...</td>
                    </tr>
                  ) : filteredTransactions.length === 0 ? (
                    <tr>
                      <td colSpan="7" className="text-center">No transactions found</td>
                    </tr>
                  ) : (
                    filteredTransactions.map((transaction) => (
                      <tr key={transaction.RFIDNumber}>
                        <td>
                          <input
                            type="checkbox"
                            checked={selectedItems.includes(transaction.Itemcode)}
                            onChange={(e) => {
                              if (e.target.checked) {
                                setSelectedItems([...selectedItems, transaction.Itemcode]);
                              } else {
                                setSelectedItems(selectedItems.filter(id => id !== transaction.Itemcode));
                              }
                            }}
                          />
                        </td>
                        <td>{transaction.RFIDNumber}</td>
                        <td>{transaction.Itemcode}</td>
                        <td>{transaction.category_id}</td>
                        <td>{transaction.product_id}</td>
                        <td>
                          <span className={`badge bg-${transaction.status === 'Active' ? 'success' : 'secondary'}`}>
                            {transaction.status}
                          </span>
                        </td>
                        <td>
                          <button
                            className="btn btn-sm btn-outline-primary me-2"
                            onClick={() => handleUpdateStatus(transaction.RFIDNumber, transaction.status === 'Active' ? 'Sold' : 'Active')}
                          >
                            <FaEdit /> {transaction.status === 'Active' ? 'Mark Sold' : 'Mark Active'}
                          </button>
                          <button
                            className="btn btn-sm btn-outline-danger"
                            onClick={() => handleDelete([transaction.Itemcode])}
                          >
                            <FaTrash />
                          </button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>

      {/* Add New Item Modal */}
      {showAddModal && (
        <div className="modal show d-block" style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
          <div className="modal-dialog modal-lg">
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title">Add New RFID Item</h5>
                <button type="button" className="btn-close" onClick={() => setShowAddModal(false)}></button>
              </div>
              <div className="modal-body">
                <div className="row g-3">
                  <div className="col-md-6">
                    <label className="form-label">RFID Number</label>
                    <input
                      type="text"
                      className="form-control"
                      value={newItem.rfidNumber}
                      onChange={(e) => setNewItem({...newItem, rfidNumber: e.target.value})}
                    />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Item Code</label>
                    <input
                      type="text"
                      className="form-control"
                      value={newItem.itemCode}
                      onChange={(e) => setNewItem({...newItem, itemCode: e.target.value})}
                    />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Category</label>
                    <input
                      type="text"
                      className="form-control"
                      value={newItem.categoryId}
                      onChange={(e) => setNewItem({...newItem, categoryId: e.target.value})}
                    />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Product</label>
                    <input
                      type="text"
                      className="form-control"
                      value={newItem.productId}
                      onChange={(e) => setNewItem({...newItem, productId: e.target.value})}
                    />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Design</label>
                    <input
                      type="text"
                      className="form-control"
                      value={newItem.designId}
                      onChange={(e) => setNewItem({...newItem, designId: e.target.value})}
                    />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Purity</label>
                    <input
                      type="text"
                      className="form-control"
                      value={newItem.purityId}
                      onChange={(e) => setNewItem({...newItem, purityId: e.target.value})}
                    />
                  </div>
                  <div className="col-md-4">
                    <label className="form-label">Gross Weight</label>
                    <input
                      type="number"
                      className="form-control"
                      value={newItem.grossWeight}
                      onChange={(e) => setNewItem({...newItem, grossWeight: e.target.value})}
                    />
                  </div>
                  <div className="col-md-4">
                    <label className="form-label">Stone Weight</label>
                    <input
                      type="number"
                      className="form-control"
                      value={newItem.stoneWeight}
                      onChange={(e) => setNewItem({...newItem, stoneWeight: e.target.value})}
                    />
                  </div>
                  <div className="col-md-4">
                    <label className="form-label">Net Weight</label>
                    <input
                      type="number"
                      className="form-control"
                      value={newItem.netWeight}
                      onChange={(e) => setNewItem({...newItem, netWeight: e.target.value})}
                    />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Box Details</label>
                    <input
                      type="text"
                      className="form-control"
                      value={newItem.boxDetails}
                      onChange={(e) => setNewItem({...newItem, boxDetails: e.target.value})}
                    />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">MRP</label>
                    <input
                      type="number"
                      className="form-control"
                      value={newItem.mrp}
                      onChange={(e) => setNewItem({...newItem, mrp: e.target.value})}
                    />
                  </div>
                </div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-secondary" onClick={() => setShowAddModal(false)}>Cancel</button>
                <button type="button" className="btn btn-primary" onClick={handleAddItem}>Add Item</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RFIDTransactions;
